          ctx.globalAlpha = lt;
          ctx.strokeRect(c.x1, c.y1, w, h);
          ctx.restore();
          if (lt > 0.6) {
            const la = (lt - 0.6) / 0.4;
            ctx.save();
            ctx.globalAlpha = la;
            const label = i + 1 + '  ' + (box.score * 100).toFixed(0) + '%';
            ctx.font = 'bold 11px -apple-system,monospace';
            const tw = ctx.measureText(label).width;
            ctx.fillStyle = isH ? 'rgba(255,149,0,0.88)' : 'rgba(52,199,89,0.88)';
            ctx.beginPath();
            ctx.roundRect(c.x1, c.y1 - 22, tw + 12, 20, 4);
            ctx.fill();
            ctx.fillStyle = '#fff';
            ctx.fillText(label, c.x1 + 6, c.y1 - 7);
            ctx.restore();
          }
        });
        if (prog < total) requestAnimationFrame(draw);
      };
      requestAnimationFrame(draw);
    },
