      const farm = this.farms.find(f => f.id === farmId);
      if (!farm) return;
      if (!confirm(`确定要删除猪场"${farm.name}"吗？`)) return;
      try {
        const response = await deleteFarm(farmId);
        if (response.success) {
          this.farms = this.farms.filter(f => f.id !== farmId);
          if (this.selectedFarmId === farmId) {
            this.selectedFarmId = null;
          }
          this.$store.commit('ADD_LOG', {
            msg: `成功删除猪场：${farm.name}`,
            type: 'success'
          });
        }
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '删除猪场失败：' + err.message,
          type: 'error'
        });
      }
    },
    formatFarmDate(dateStr) {
      if (!dateStr) return '';
      const date = new Date(dateStr);
      return date.toLocaleDateString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      });
    },
    // 历史图片相关方法
    async loadHistoryImages() {
      try {
        const response = await fetch('/api/detection-records?page=1&page_size=10');
        const data = await response.json();
        if (data.success) {
          // 对于每个记录，获取详细信息以获取标注图片
          const historyImages = [];
          for (const record of data.data) {
            const detailResponse = await fetch(`/api/detection-records/${record.id}`);
            const detailData = await detailResponse.json();
            if (detailData.success) {
              historyImages.push({
                id: record.id,
                image_name: record.image_name,
                predicted_count: record.predicted_count,
                processing_time_ms: record.processing_time_ms,
                created_at: record.created_at,
                annotated_image: detailData.annotated_image
              });
            }
          }
          this.$store.commit('SET_HISTORY_IMAGES', historyImages);
        }
      } catch (error) {
        console.error('加载历史记录失败:', error);
      }
    },
    viewHistoryImage(index) {
      this.$store.commit('SET_CURRENT_HISTORY_INDEX', index);
      const image = this.$store.state.historyImages[index];
